import { describe, it, expect } from "vitest";
import { execSync } from "child_process";

const claimOffice = (input: string): string => {
  return execSync(`echo '${input.replace(/'/g, "'\\''")}' | pnpm tsx src/cli.ts`, {
    encoding: "utf-8",
    cwd: "/home/experimenter/experiments/runs/2026-05-26_07-28-08_claim-office-example-mapping_v5.1-testlist-scope-fix-oc_mistral-medium-3-5-2",
  }).trim();
};

describe("CLI claim-office", () => {
  describe("Empty and edge cases", () => {
    it.todo("should return premium 5 for empty item list");
    it.todo("should exit with error for unknown item type in quote");
    it.todo("should exit with error for claim referencing item not in policy");
    it.todo("should exit with error for claim with negative damage amount");
    it.todo("should exit with error for claim with more damage entries of a type than policy covers");
  });

  describe("Quote - Item base premiums", () => {
    it.todo("should return 105 for single sword (100 + 5 fee)");
    it.todo("should return 65 for single amulet (60 + 5 fee)");
    it.todo("should return 85 for single staff (80 + 5 fee)");
    it.todo("should return 45 for single potion (40 + 5 fee)");
    it.todo("should return 30 for single rune (25 + 5 fee)");
    it.todo("should return 30 for single moonstone (25 + 5 fee)");
  });

  describe("Quote - Component building blocks", () => {
    it.todo("should return 55 for 2 runes (50 + 5 fee)");
    it.todo("should return 65 for 3 runes block (60 + 5 fee)");
    it.todo("should return 105 for 4 runes (100 + 5 fee)");
    it.todo("should return 180 for 7 runes (175 + 5 fee)");
    it.todo("should return 80 for 2 runes + 1 moonstone (75 + 5 fee)");
    it.todo("should return 125 for 3 runes + 3 moonstones (120 + 5 fee)");
  });

  describe("Quote - Item-specific modifiers", () => {
    it.todo("should return 155 for cursed sword (100 + 50 + 5 fee)");
    it.todo("should return 135 for sword enchantment 5 (100 + 30 + 5 fee)");
    it.todo("should return 185 for cursed sword enchantment 5 (100 + 50 + 30 + 5 fee)");
    it.todo("should return 105 for sword enchantment 4 (100 + 5 fee, no high enchant)");
    it.todo("should return 95 for cursed amulet (60 + 30 + 5 fee)");
  });

  describe("Quote - Policy-wide modifiers", () => {
    it.todo("should apply 20% loyalty discount for customer with 2 years");
    it.todo("should apply 10% first insurance surcharge");
    it.todo("should apply 15% follow-up contract discount");
  });

  describe("Quote - Modifier scope", () => {
    it.todo("should apply cursed surcharge only to cursed item in multi-item policy");
  });

  describe("Quote - Rounding", () => {
    it.todo("should round up 197.5 to 198");
    it.todo("should round down 197.4 to 197");
  });

  describe("Quote - Integration examples", () => {
    it.todo("should compute 165 for newcomer with cursed sword");
    it.todo("should compute 160 for long-standing customer second contract with cursed sword enchantment 7");
  });

  describe("Claim - Basic", () => {
    it.todo("should return payout 400 and remainingCap 1600 for sword damage 500");
    it.todo("should return payout 100 and remainingCap 1800 for rune damage 200");
  });

  describe("Claim - Deductible", () => {
    it.todo("should apply 100 deductible per damage event");
    it.todo("should apply deductible once per damaged item");
  });

  describe("Claim - Special clauses", () => {
    it.todo("should reimburse 50% for enchantment >= 8");
    it.todo("should fully reimburse dragon material");
    it.todo("should prioritize 50% rule when both apply");
  });

  describe("Claim - Cap exhaustion", () => {
    it.todo("should cap payout at remaining cap");
    it.todo("should track remaining cap across multiple claims");
  });

  describe("Claim - Rounding", () => {
    it.todo("should round down payout 350.5 to 350");
  });

  describe("Multi-step scenarios", () => {
    it.todo("should process quote then claim in sequence");
    it.todo("should track cap across multiple claims on same policy");
  });
});

