    if (base !== undefined) totalBase += base;
  }

  if (totalBase > 0) return { premium: totalBase + 5 };
  return {};
});

input.newString:
const basePremiums = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };

const results = scenario.steps.map((step) => {
  if (step.op !== "quote") return {};
  if (step.items.length === 0) return { premium: 5 };

  let totalBase = 0;
  const counts = {};

  for (const item of step.items) {
    const type = item.type;
    const base = basePremiums[type];
    if (base !== undefined) {
      counts[type] = (counts[type] || 0) + 1;
    }
  }

  for (const [type, count] of Object.entries(counts)) {
    const base = basePremiums[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    totalBase += blocks * 60;
    totalBase += remainder * base;
  }

  if (totalBase > 0) return { premium: totalBase + 5 };
  return {};
});

