    if (type !== "rune" && type !== "moonstone") continue;
    const base = basePremiums[type];
    if (count % 3 === 0) {
      totalBase += (count / 3) * 60;
    } else {
      totalBase += count * base;
    }
  }

  if (totalBase > 0) return { premium: totalBase + 5 };
  return {};
});

input.newString:
const results = scenario.steps.map((step) => {
  if (step.op !== "quote") return {};
  if (step.items.length === 0) return { premium: 5 };

  let totalBase = 0;
  const componentCounts = { rune: 0, moonstone: 0 };

  for (const item of step.items) {
    const type = item.type;
    const base = basePremiums[type];
    if (base === undefined) continue;

    if (type === "rune" || type === "moonstone") {
      componentCounts[type]++;
      continue;
    }

    let itemBase = base;
    if (item.cursed) {
      itemBase += Math.floor(itemBase * 0.5);
    }
    totalBase += itemBase;
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 0) continue;
    const base = basePremiums[type];
    if (count % 3 === 0) {
      totalBase += (count / 3) * 60;
    } else {
      totalBase += count * base;
    }
  }

  if (totalBase > 0) return { premium: totalBase + 5 };
  return {};
});

