      policyBase += count * base;
    }
  }

  let total = policyBase + itemModifiers;

  total += Math.floor(policyBase * 0.1);

  if (scenario.customer.yearsWithMHPCO >= 2) {
    total -= Math.floor(policyBase * 0.2);
  }

  if (quoteCount > 1) {
    total -= Math.floor(policyBase * 0.15);
  }

